#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
typedef double LL;
namespace jr_zlw
{
	inline int read()
	{
		int res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		return flag ? -res : res ;
	}
	inline LL abs(LL x){return x<0?-x:x;}
	struct Matrix
	{
		LL a[13][13],n,*s[13];
		inline Matrix(int N=0,bool x=0){n=N;memset(a,0,sizeof(a));if(x)rep(1,n,i)a[i][i]=1;}
		inline void Swap(const int a,const int b){LL *tmp=s[a];s[a]=s[b];s[b]=tmp;}
		inline LL Det()
		{
			rep(1,n,i)s[i]=a[i];rep(1,n,i)
			{
				int k=i;rep(i+1,n,j)if(s[k][i]<s[j][i])k=j;
				if(k^i)Swap(i,k);if(abs(a[i][i]<1e-8))return 0;
				rep(i+1,n,j)
				{
					LL qwq=s[j][i]/s[i][i];
					rep(i,n+1,k)s[j][k]-=s[i][k]*qwq;
				} 
			}
			
			LL res=1;rep(1,n,i)res*=s[i][i];return res;
		}
		
	};
	
	inline void Solve()
	{
		Matrix q;q.n=read()-1;int m=read();
		rep(1,m,i){int x=read(),y=read();++q.a[x][x];--q.a[x][y];--q.a[y][x];++q.a[y][y];}
		printf("%.0lf\n",q.Det());return;
	}
	inline void mian()
	{
//		freopen("data.txt","r",stdin);
//		freopen("mine.txt","w",stdout);
		int T=read();while(T--)Solve();
	}
}
int main(){jr_zlw::mian();return 0;}
